import{_ as t,H as e,f as a,i}from"./chunks/framework.DLd0CbzH.js";const k=JSON.parse('{"title":"给 Cursor CLI 加个 Web 历史查看器：cchv-server 适配新版数据格式实战","description":"","frontmatter":{"title":"给 Cursor CLI 加个 Web 历史查看器：cchv-server 适配新版数据格式实战","date":"2026-06-08T00:00:00.000Z","tags":["Cursor CLI","cchv-server","开源","实践","DevTools"],"categories":["工具链"]},"headers":[],"relativePath":"2026/06/08/cchv-server-cursor-cli-adaptor.md","filePath":"2026/06/08/cchv-server-cursor-cli-adaptor.md"}'),r={name:"2026/06/08/cchv-server-cursor-cli-adaptor.md"};function n(o,s,d,l,h,p){return e(),a("div",null,[...s[0]||(s[0]=[i(`<blockquote><p>用 cchv-server 同时浏览 Claude Code / Codex / OpenCode / Cursor 的会话历史，但遇到新版 Cursor CLI 数据格式不兼容的问题。本文记录适配过程和思路。</p></blockquote><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>我日常同时用几个 AI coding agent，会话散在各处：</p><table tabindex="0"><thead><tr><th>Agent</th><th>数据路径</th><th>格式</th></tr></thead><tbody><tr><td>Claude Code</td><td><code>~/.claude/projects/</code></td><td>JSONL</td></tr><tr><td>Codex CLI</td><td><code>~/.codex/sessions/</code></td><td>JSONL</td></tr><tr><td>OpenCode</td><td><code>~/.local/share/opencode/</code></td><td>SQLite</td></tr><tr><td>Cursor CLI (2026版)</td><td><code>~/.cursor/projects/</code></td><td>JSONL</td></tr></tbody></table><p>2026 年 5 月以后，Cursor CLI 改用新版数据目录（<code>~/.cursor/projects/</code>），不再使用旧版 VS Code 风格的 <code>~/.config/Cursor/User/workspaceStorage/</code>。而 <a href="https://github.com/jhlee0409/claude-code-history-viewer" target="_blank" rel="noreferrer">cchv-server</a> 当时还不支持这个新路径。</p><h2 id="尝试方案一-改-rust-代码" tabindex="-1">尝试方案一：改 Rust 代码 <a class="header-anchor" href="#尝试方案一-改-rust-代码" aria-label="Permalink to &quot;尝试方案一：改 Rust 代码&quot;">​</a></h2><p>cchv-server 是 Rust + Tauri 写的，Cursor provider 在 <code>src-tauri/src/providers/cursor.rs</code>。最直接的做法是修改 <code>detect()</code> 和 <code>scan_projects()</code> 函数，加入对新版 <code>~/.cursor/projects/agent-transcripts/</code> JSONL 格式的支持。</p><p>代码写好了，但第一次编译（<code>cargo build --release</code>）在 Biren SDK 环境踩到两个坑：</p><ol><li><strong>PKG_CONFIG_PATH 被 Biren SDK &quot;污染&quot;</strong>（<code>/usr/local/birensupa/base/.../brgstreamer/lib/.../pkgconfig</code>），导致找不到系统 <code>dbus-1.pc</code></li><li><strong>依赖下载量大</strong>（几十个 crate），在第一次编译时耗时很长</li></ol><p>后来装了 <code>libdbus-1-dev</code> 应该能解决，但等编译太久了，决定先上实用方案。</p><h2 id="最终方案-格式转换脚本" tabindex="-1">最终方案：格式转换脚本 <a class="header-anchor" href="#最终方案-格式转换脚本" aria-label="Permalink to &quot;最终方案：格式转换脚本&quot;">​</a></h2><p>思路：新版 Cursor 的 JSONL 格式和旧版的 SQLite workspace 结构本质是等价的——都是 <code>composerId -&gt; bubbles[] -&gt; messages[]</code> 的映射。写一个 Python 脚本把 JSONL 转成旧版 SQLite 格式，cchv-server 一行代码都不用改。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cursor-cli-to-cchv.py (简化版)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 读取 ~/.cursor/projects/&lt;projet&gt;/agent-trascripts/&lt;session&gt;/*.jsonl</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 写入 ~/.config/Cursor/User/workspaceStorage/&lt;hash&gt;/state.vscdb</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># + workspace.json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> convert_one_session</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cosql_path):</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mesages </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> read_jsonl(josnl_path)             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 每行一个 JSON</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bubles </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> []                                    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 转成 Cursor bubble 格式</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> msg </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mesages:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        buble </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            &quot;bubleId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cli-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">idx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> msg[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;role&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;user&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> else</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            &quot;text&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: extract_text(msg),</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            &quot;toolFormerData&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">...</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> has_tool_use </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> None</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        bubles.append(buble)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 写入 SQLite (composer.composerData + cursorDiskKV)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    write_to_db(db_path, session_id, bubles)</span></span></code></pre></div><p>关键点：</p><ul><li><strong>workspace.json</strong>：写入 <code>{&quot;folder&quot;: &quot;file:///home/.../.cursor/projects/&lt;project&gt;&quot;}</code>，cchv-server 据此显示项目名</li><li><strong>composer.composerData</strong>：存储会话列表（id、name、时间戳、isArchived）</li><li><strong>cursorDiskKV</strong>：存储每个 bubble 的具体内容</li><li><strong>globalStorage/state.vscdb</strong>：cchv-server 的 <code>detect()</code> 检查这个文件是否存在——创建空的 SQLite DB 即可</li></ul><p>转换完后 ，14 个项目、119 个会话全部出现在 WebUI 上。</p><h2 id="定时自动同步" tabindex="-1">定时自动同步 <a class="header-anchor" href="#定时自动同步" aria-label="Permalink to &quot;定时自动同步&quot;">​</a></h2><p>新 Cursor 会话每分钟都在产生，我配了一个 cron 每 2 分钟自动跑转换脚本，零开销模式（<code>no_agent: true</code>，直接跑 shell 脚本）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hermes cron create --name cursor-sync --no-agent \\</span></span>
<span class="line"><span>  --script cursor-sync.sh \\</span></span>
<span class="line"><span>  --schedule &quot;every 2min&quot;</span></span></code></pre></div><h2 id="踩坑记录" tabindex="-1">踩坑记录 <a class="header-anchor" href="#踩坑记录" aria-label="Permalink to &quot;踩坑记录&quot;">​</a></h2><table tabindex="0"><thead><tr><th>坑</th><th>表现</th><th>解决</th></tr></thead><tbody><tr><td><code>detect()</code> 返回 <code>is_available: false</code></td><td>Cursor 不在 provider 列表里</td><td>创建 <code>globleStorage/state.vscdb</code> 空文件</td></tr><tr><td>Biren SDK 污染 PKG_CONFIG_PATH</td><td>找不到 system dbus-1.pc</td><td>装 <code>libdbus-1-dev</code> 或用 <code>env -u</code> 清环境</td></tr><tr><td>前端 SSE 自动刷新</td><td>打开会话页面反复闪</td><td>关闭 watcher（修改前端 UseFileWacher.ts）</td></tr><tr><td>SQLite WAL/SHM 文件触发 inotify</td><td>opencode.db-shm 每秒写 → 不停发 SSE 事件</td><td>同上，关闭前端 SSE 订阅</td></tr><tr><td>打开 Cursor 会话 crash: &quot;Composer not found&quot;</td><td>点击会话就崩</td><td>旧版 <code>load_old_messages()</code> 读 <code>globalStorage/state.vscdb</code> 的 <code>cursorDiskKV</code> 表，但新版数据在 workspace 级 DB → 把 bubble 数据写入 global DB</td></tr></tbody></table><h2 id="最终效果" tabindex="-1">最终效果 <a class="header-anchor" href="#最终效果" aria-label="Permalink to &quot;最终效果&quot;">​</a></h2><p>访问局域网 WebUI 就能在一个页面里浏览所有 4 个 agent 的会话历史，按项目分组、按时间排序、支持搜索。</p><table tabindex="0"><thead><tr><th>Provider</th><th>项目数</th><th>会话数</th></tr></thead><tbody><tr><td>Claude Code</td><td>20</td><td>~200+</td></tr><tr><td>Codex CLI</td><td>6</td><td>数十</td></tr><tr><td>OpenCode</td><td>3</td><td>中等</td></tr><tr><td>Cursor CLI</td><td>14</td><td>119</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>等 Rust 编译完成后，还是可以用修改后的原生 provider 直接读取新版格式，省掉转换这层中间步骤。不过对于目前的使用量来说，转换脚本 + cron 自动同步已经够用了。</p><hr><p><strong>相关仓库</strong>：<a href="https://github.com/jhlee0409/claude-code-history-viewer" target="_blank" rel="noreferrer">jhlee0409/claude-code-history-viewer</a><strong>转换脚本</strong>：<a href="https://github.com/GonChen/ws2/blob/main/claude-code-history-viewer/cursor-cli-to-cchv.py" target="_blank" rel="noreferrer">cursor-cli-to-cchv.py</a></p>`,28)])])}const u=t(r,[["render",n]]);export{k as __pageData,u as default};
